import React, { useState, useEffect, useCallback } from 'react';
import { Box, List, ListItem, ListItemText, ListItemButton, Alert, CircularProgress, IconButton, InputAdornment } from '@mui/material';
import { Search as SearchIcon } from '@mui/icons-material';
import FAWDrawer from '../FAWDrawer';
import FAWTypography from '../FAWTypography';
import FAWInput from '../FAWInput';
import FAWSkeleton from '../FAWSkeleton';

/**
 * Recursive component to render hierarchical task tree (matches legacy structure)
 */
const TaskTreeItem = ({ task, onTaskClick, level = 0 }) => {
  const paddingLeft = level * 20 + 10; // 10px base + 20px per level
  
  return (
    <li style={{ listStyle: 'none', margin: '3px 0' }}>
      {task.IsHighlighted ? (
        <a
          href="#"
          onClick={(e) => {
            e.preventDefault();
            onTaskClick(task.Id);
          }}
          style={{
            paddingLeft: `${paddingLeft}px`,
            color: '#4c9be3',
            fontWeight: 900,
            textDecoration: 'none',
            cursor: 'pointer',
            display: 'block'
          }}
          onMouseEnter={(e) => {
            e.target.style.textDecoration = 'underline';
          }}
          onMouseLeave={(e) => {
            e.target.style.textDecoration = 'none';
          }}
        >
          {task.Name}
        </a>
      ) : (
        <span style={{ paddingLeft: `${paddingLeft}px`, display: 'block' }}>
          {task.Name}
        </span>
      )}
      
      {task.Children && task.Children.length > 0 && (
        <ul style={{ listStyle: 'none', margin: 0, padding: 0 }}>
          {task.Children.map((child) => (
            <TaskTreeItem
              key={child.Id}
              task={child}
              onTaskClick={onTaskClick}
              level={level + 1}
            />
          ))}
        </ul>
      )}
    </li>
  );
};

/**
 * SearchUDFDrawer Component
 * Drawer for searching additional fields in workflows, snippets, and work items
 * Follows the same design pattern as SearchFieldDrawer
 */
const SearchUDFDrawer = ({ 
  open, 
  onClose, 
  entityId, // Can be workflowId, snippetId, or workItemId
  entityType = 'workflow', // 'workflow', 'snippet', or 'workitem'
  onNavigateToTask
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [searchResults, setSearchResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // Perform the actual search
  const performSearch = useCallback(async (term) => {
    if (!entityId) {
      return;
    }
    
    // Empty term is valid - shows all tasks (like legacy)
    const searchTerm = term ? term.trim() : '';

    setLoading(true);
    setError(null);
    setSearchResults([]);

    try {
      // Determine the correct API endpoint based on entity type
      let endpoint;
      let bodyParams;
      
      if (entityType === 'snippet') {
        endpoint = '/WorkflowTaskDefSnippet/SearchUDFs';
        bodyParams = { snippetId: entityId, searchTerm: searchTerm };
      } else if (entityType === 'workitem') {
        endpoint = '/WorkItem/SearchUDFsApi';
        bodyParams = { workItemId: entityId, term: searchTerm };
      } else {
        endpoint = '/WorkflowDef/SearchUDFsApi';
        bodyParams = { workflowDefId: entityId, term: searchTerm };
      }

      const response = await fetch(endpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams(bodyParams)
      });

      if (!response.ok) {
        throw new Error('Search request failed');
      }

      const data = await response.json();
      
      if (!data.success) {
        throw new Error(data.message || 'Search failed');
      }

      // Results are already in hierarchical format from API
      setSearchResults(data.results || []);
    } catch (err) {
      setError('Failed to search fields. Please try again.');
      console.error('Search UDF error:', err);
    } finally {
      setLoading(false);
    }
  }, [entityId, entityType]);

  // Manual search trigger (for button click or Enter key)
  // Matches legacy: only searches if term exists
  const handleSearch = useCallback(() => {
    if (!entityId) {
      return;
    }
    
    const trimmedTerm = searchTerm.trim();
    // Legacy behavior: only search if term exists
    if (trimmedTerm) {
      performSearch(trimmedTerm);
    }
  }, [searchTerm, performSearch, entityId]);

  // Handle result click
  const handleResultClick = useCallback((taskId) => {
    // Use the provided navigation handler or dispatch a custom event
    if (onNavigateToTask) {
      onNavigateToTask(taskId, entityId);
    } else {
      const event = new CustomEvent('navigateToTask', {
        detail: { 
          taskId: taskId,
          ...(entityType === 'snippet' ? { snippetId: entityId } : 
              entityType === 'workitem' ? { workItemId: entityId } : 
              { workflowId: entityId })
        }
      });
      window.dispatchEvent(event);
    }
    
    onClose();
  }, [onNavigateToTask, onClose, entityId, entityType]);

  // Handle drawer close
  const handleClose = useCallback(() => {
    setSearchTerm('');
    setSearchResults([]);
    setError(null);
    onClose();
  }, [onClose]);

  // Handle Enter key press (immediate search)
  const handleKeyPress = useCallback((event) => {
    if (event.key === 'Enter') {
      handleSearch();
    }
  }, [handleSearch]);

  // Load initial data when drawer opens (matches legacy: workflowDefUdfs called on modal open)
  // Reset state when drawer closes
  useEffect(() => {
    if (open && entityId) {
      // Load all tasks when drawer opens (empty term = show all tasks)
      performSearch('');
    } else if (!open) {
      setSearchTerm('');
      setSearchResults([]);
      setError(null);
    }
  }, [open, entityId, performSearch]);

  return (
    <FAWDrawer
      open={open}
      onClose={handleClose}
      title="Find Additional Fields"
      anchor="right"
      width={400}
      actions={[
        {
          text: 'Cancel',
          variant: 'outlined',
          onClick: handleClose
        }
      ]}
    >
      <Box sx={{ p: 3 }}>
        {/* Search Input with Search Icon Button */}
        <FAWInput
          label="Search for field"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          placeholder="Enter search term..."
          fullWidth
          onKeyPress={handleKeyPress}
          labelSx={{ fontSize: '14px', fontWeight: 500 }}
          sx={{ mb: 2 }}
          endAdornment={
            <InputAdornment position="end">
              <IconButton
                onClick={handleSearch}
                disabled={loading || !entityId}
                edge="end"
                sx={{ 
                  color: loading || !entityId ? 'action.disabled' : 'primary.main',
                  '&:hover': {
                    backgroundColor: 'action.hover'
                  }
                }}
                aria-label="search"
              >
                <SearchIcon />
              </IconButton>
            </InputAdornment>
          }
        />

        {/* Error Display */}
        {error && (
          <Alert severity="error" sx={{ mb: 2 }}>
            {error}
          </Alert>
        )}

        {/* Instructions */}
        <FAWTypography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
          Click a highlighted task to navigate to it.
        </FAWTypography>

        {/* Loading State - Skeleton */}
        {loading && (
          <Box sx={{ 
            maxHeight: 400, 
            overflowY: 'auto',
            border: '1px solid #e0e0e0',
            borderRadius: 1,
            p: 1
          }}>
            <FAWSkeleton variant="tree" />
          </Box>
        )}

        {/* Search Results - Hierarchical Tree */}
        {!loading && searchResults.length > 0 && (
          <Box sx={{ 
            maxHeight: 400, 
            overflowY: 'auto',
            border: '1px solid #e0e0e0',
            borderRadius: 1,
            p: 1
          }}>
            <ul style={{ listStyle: 'none', margin: 0, padding: 0 }}>
              {searchResults.map((task) => (
                <TaskTreeItem
                  key={task.Id}
                  task={task}
                  onTaskClick={handleResultClick}
                  level={0}
                />
              ))}
            </ul>
          </Box>
        )}

        {/* No Results */}
        {!loading && searchTerm && searchResults.length === 0 && !error && (
          <Alert severity="warning">
            No fields found matching "{searchTerm}"
          </Alert>
        )}

      </Box>
    </FAWDrawer>
  );
};

export default SearchUDFDrawer;

